mapper.update:
update board set btitle=#{btitle}, bcontent=#{bcontent}, bdate=sysdate
, battachoname=#{battachoname}, battachsname=#{battachsname}, battachtype=#{battachtype}, battachdata=#{battachdata}
where bno=#{bno}

mapper.select:

    	select * from (
	        select rownum rnum, bno, btitle, bwriter, bdate, bhitcount
	        from (
	            select bno, btitle, bwriter, bdate, bhitcount
	            from board
	            order by bno desc
	        )
	        where rownum <= #{endRowNo}
	    )
	    where rnum >= #{startRowNo}
